drop extension if exists "pg_net";

do $$
begin
  if not exists (select 1 from pg_roles where rolname = 'prisma') then
    create role prisma;
  end if;
end
$$;

create schema if not exists "dev";

create type "public"."work_type" as enum ('task', 'misc');


  create table "public"."roles" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "name" text not null
      );


alter table "public"."roles" enable row level security;


  create table "public"."users" (
    "name" text,
    "email" text,
    "birth_date" date,
    "created_at" timestamp with time zone not null default now(),
    "is_active" boolean default false,
    "on_leave" boolean default true,
    "street" text,
    "postal_code" text,
    "city" text,
    "country" text,
    "phone" text,
    "profile_picture" text,
    "room_number" smallint,
    "seniority" smallint,
    "id" uuid not null,
    "role_id" bigint,
    "school_id" uuid,
    "study_id" uuid
      );


alter table "public"."users" enable row level security;


  create table "public"."work_assignments" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "hours_used" real,
    "approved_state" smallint not null default '0'::smallint,
    "approval_comment" text,
    "approved_by_uuid" uuid,
    "user_uuid" uuid not null,
    "work_id" bigint not null
      );


alter table "public"."work_assignments" enable row level security;


  create table "public"."work_categories" (
    "id" bigint generated by default as identity not null,
    "name" text,
    "description" text,
    "color" text,
    "is_active" boolean default true,
    "created_at" timestamp with time zone not null default now()
      );


alter table "public"."work_categories" enable row level security;


  create table "public"."work_items" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "work_category_id" bigint not null,
    "type" public.work_type,
    "title" text not null,
    "description" text
      );


alter table "public"."work_items" enable row level security;


  create table "public"."work_misc" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now()
      );


alter table "public"."work_misc" enable row level security;


  create table "public"."work_tasks" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "deadline" date,
    "time_estimate" smallint,
    "contact_person_uuid" uuid,
    "max_participants" smallint default 1
      );


alter table "public"."work_tasks" enable row level security;

CREATE UNIQUE INDEX roles_pkey ON public.roles USING btree (id);

CREATE UNIQUE INDEX task_pkey ON public.work_tasks USING btree (id);

CREATE UNIQUE INDEX users_pkey ON public.users USING btree (id);

CREATE UNIQUE INDEX work_assignments_pkey ON public.work_assignments USING btree (id);

CREATE UNIQUE INDEX work_categories_pkey ON public.work_categories USING btree (id);

CREATE UNIQUE INDEX work_items_pkey ON public.work_items USING btree (id);

CREATE UNIQUE INDEX work_misc_pkey ON public.work_misc USING btree (id);

alter table "public"."roles" add constraint "roles_pkey" PRIMARY KEY using index "roles_pkey";

alter table "public"."users" add constraint "users_pkey" PRIMARY KEY using index "users_pkey";

alter table "public"."work_assignments" add constraint "work_assignments_pkey" PRIMARY KEY using index "work_assignments_pkey";

alter table "public"."work_categories" add constraint "work_categories_pkey" PRIMARY KEY using index "work_categories_pkey";

alter table "public"."work_items" add constraint "work_items_pkey" PRIMARY KEY using index "work_items_pkey";

alter table "public"."work_misc" add constraint "work_misc_pkey" PRIMARY KEY using index "work_misc_pkey";

alter table "public"."work_tasks" add constraint "task_pkey" PRIMARY KEY using index "task_pkey";

alter table "public"."users" add constraint "users_role_id_fkey" FOREIGN KEY (role_id) REFERENCES public.roles(id) ON UPDATE CASCADE ON DELETE SET NULL not valid;

alter table "public"."users" validate constraint "users_role_id_fkey";

alter table "public"."users" add constraint "users_school_id_fkey" FOREIGN KEY (school_id) REFERENCES public.schools(id) not valid;

alter table "public"."users" validate constraint "users_school_id_fkey";

alter table "public"."users" add constraint "users_study_id_fkey" FOREIGN KEY (study_id) REFERENCES public.studies(id) not valid;

alter table "public"."users" validate constraint "users_study_id_fkey";

alter table "public"."work_assignments" add constraint "work_assignments_approved_by_uuid_fkey" FOREIGN KEY (approved_by_uuid) REFERENCES public.users(id) not valid;

alter table "public"."work_assignments" validate constraint "work_assignments_approved_by_uuid_fkey";

alter table "public"."work_assignments" add constraint "work_assignments_user_uuid_fkey" FOREIGN KEY (user_uuid) REFERENCES public.users(id) not valid;

alter table "public"."work_assignments" validate constraint "work_assignments_user_uuid_fkey";

alter table "public"."work_assignments" add constraint "work_assignments_work_id_fkey" FOREIGN KEY (work_id) REFERENCES public.work_items(id) not valid;

alter table "public"."work_assignments" validate constraint "work_assignments_work_id_fkey";

alter table "public"."work_items" add constraint "work_items_work_category_id_fkey" FOREIGN KEY (work_category_id) REFERENCES public.work_categories(id) not valid;

alter table "public"."work_items" validate constraint "work_items_work_category_id_fkey";

alter table "public"."work_misc" add constraint "work_misc_id_fkey" FOREIGN KEY (id) REFERENCES public.work_items(id) not valid;

alter table "public"."work_misc" validate constraint "work_misc_id_fkey";

alter table "public"."work_tasks" add constraint "work_tasks_contact_person_uuid_fkey" FOREIGN KEY (contact_person_uuid) REFERENCES public.users(id) not valid;

alter table "public"."work_tasks" validate constraint "work_tasks_contact_person_uuid_fkey";

alter table "public"."work_tasks" add constraint "work_tasks_id_fkey" FOREIGN KEY (id) REFERENCES public.work_items(id) not valid;

alter table "public"."work_tasks" validate constraint "work_tasks_id_fkey";

