  create policy "Authenticated users can read roles"
  on "public"."roles"
  as permissive
  for select
  to authenticated
using (true);



  create policy "Admins can update any user"
  on "public"."users"
  as permissive
  for update
  to authenticated
using ((EXISTS ( SELECT 1
   FROM (public.users u
     JOIN public.roles r ON ((u.role_id = r.id)))
  WHERE ((u.id = auth.uid()) AND (r.name = ANY (ARRAY['Admin'::text, 'Data'::text, 'Regisjef'::text, 'Romsjef'::text]))))))
with check ((EXISTS ( SELECT 1
   FROM (public.users u
     JOIN public.roles r ON ((u.role_id = r.id)))
  WHERE ((u.id = auth.uid()) AND (r.name = ANY (ARRAY['Admin'::text, 'Data'::text, 'Regisjef'::text, 'Romsjef'::text]))))));



  create policy "Authenticated users can read all users"
  on "public"."users"
  as permissive
  for select
  to authenticated
using (true);



  create policy "Managers can delete non-admin users"
  on "public"."users"
  as permissive
  for delete
  to authenticated
using (((EXISTS ( SELECT 1
   FROM (public.users u
     JOIN public.roles r ON ((u.role_id = r.id)))
  WHERE ((u.id = auth.uid()) AND (r.name = ANY (ARRAY['Admin'::text, 'Data'::text, 'Regisjef'::text]))))) AND (NOT (EXISTS ( SELECT 1
   FROM public.roles r
  WHERE ((r.id = users.role_id) AND (r.name = 'Admin'::text)))))));



  create policy "Users can update own profile"
  on "public"."users"
  as permissive
  for update
  to authenticated
using ((auth.uid() = id))
with check ((auth.uid() = id));



  create policy "Authenticated users can read assignments"
  on "public"."work_assignments"
